```class Solution {
public:
    int minSwaps(vector<int>& nums) {
        int n = nums.size();
        int ones = 0;
        for (int i = 0; i < n; i++) {
            ones += nums[i];
        }
        int currOnes = 0;
        int res = n;
        for (int i = 0; i < n; i++) {
            currOnes += nums[i];
            res = min(res, ones - currOnes + min(i, n - i));
        }
        return res;
    }
};
